display.text:
#!/usr/bin/env node
// ╔══════════════════════════════════════════════════════════════════════════╗
// ║ Deep Context Loop Lock                                                   ║
// ╚══════════════════════════════════════════════════════════════════════════╝
// Thin host-facing wrapper over the deep-loop-runtime loop-lock helper so the
// host-driven context loop gets single-writer, cross-session advisory locking
// (stale-lock reclaim + clean release) from the same source of truth the mature
// loops use, instead of a prose-only lock step.
//
// INTENTIONAL DIVERGENCE from the runtime adapter
// (deep-loop-runtime/scripts/loop-lock.cjs), not accidental drift:
//   - Flag contract: --lock / --packet / --owner here, vs the runtime
//     adapter's --lock-path / --packet-id / --owner-pid. Do NOT copy
//     invocations between the two loops; the wrong flag shape silently fails
//     (exit 3). deep_context_auto/confirm.yaml call THIS wrapper's flag shape.
//   - Default TTL: 3600000ms (1h) here vs 300000ms (5min) in the runtime
//     adapter. The host-driven context loop has no single long-lived process
//     holding the lock for heartbeat refresh, so it needs a wider stale window.
//   - Loading: in-process require() (no re-exec) so a host that already runs
//     under tsx can hold the lock for the session, vs the adapter's
//     dynamic import() on a fresh process per invocation.
// Both wrap the SAME lib/deep-loop/loop-lock.ts, so the lock format and
// stale-reclaim semantics are shared; only the CLI surface and default TTL
// differ. Keep this note and the runtime adapter's note in sync if either side
// changes.

'use strict';

// ─────────────────────────────────────────────────────────────────────────────
// 1. IMPORTS
// ─────────────────────────────────────────────────────────────────────────────

const path = require('node:path');

// In-process tsx CJS register so this dual-use script can import the runtime's
// TypeScript loop-lock helper without re-execing (safe to require() as a module).
const TSX_CJS_REGISTER = path.join(__dirname, '..', '..', '..', 'system-spec-kit', 'scripts', 'node_modules', 'tsx', 'dist', 'cjs', 'index.cjs');
const RUNTIME_LOOP_LOCK = path.join(__dirname, '..', '..', '..', 'deep-loop-runtime', 'lib', 'deep-loop', 'loop-lock.ts');

// ─────────────────────────────────────────────────────────────────────────────
// 2. HELPERS
// ─────────────────────────────────────────────────────────────────────────────

function loadLoopLock() {
  require(TSX_CJS_REGISTER);
  return require(RUNTIME_LOOP_LOCK);
}

function parseArgs(argv) {
  const args = {};
  for (let i = 0; i < argv.length; i += 1) {
    const token = argv[i];
    if (!token.startsWith('--')) continue;
    const key = token.slice(2);
    const next = argv[i + 1];
    if (next === undefined || next.startsWith('--')) {
      args[key] = true;
    } else {
      args[key] = next;
      i += 1;
    }
  }
  return args;
}

function emit(payload) {
  process.stdout.write(`${JSON.stringify(payload)}\n`);
}

// ─────────────────────────────────────────────────────────────────────────────
// 3. CLI ENTRY POINT
// ─────────────────────────────────────────────────────────────────────────────

function main() {
  const [action, ...rest] = process.argv.slice(2);
  const args = parseArgs(rest);
  const lockPath = typeof args.lock === 'string' ? args.lock : null;

  if (!lockPath) {
    process.stderr.write('Usage: loop-lock.cjs <acquire|refresh|release> --lock <path> [--packet <id>] [--owner <int>] [--ttl <ms>] [--runtime <kind>]\n');
    process.exit(3);
  }

  // A host-driven loop has no single long-lived process, so the owner id is
  // host-provided and stable across the acquire/release pair (defaults to this
  // process pid for standalone use). Acquire and release MUST share the owner.
  const owner = Number.isFinite(Number(args.owner)) ? Number(args.owner) : process.pid;

  let lib;
  try {
    lib = loadLoopLock();
  } catch (error) {
    process.stderr.write(`[deep-context] loop-lock helper unavailable: ${error instanceof Error ? error.message : String(error)}\n`);
    process.exit(1);
  }

  try {
    if (action === 'acquire') {
      const now = new Date().toISOString();
      const data = {
        ownerPid: owner,
        startedAtIso: now,
        ttlMs: Number.isFinite(Number(args.ttl)) ? Number(args.ttl) : 3600000,
        lastHeartbeatIso: now,
        packetId: typeof args.packet === 'string' ? args.packet : '',
        runtimeKind: typeof args.runtime === 'string' ? args.runtime : 'main',
      };
      const result = lib.acquireLoopLock(lockPath, data);
      emit({ action, ...result });
      process.exit(result.acquired ? 0 : 1);
    } else if (action === 'refresh') {
      emit({ action, refreshed: lib.refreshLoopLock(lockPath, owner) });
      process.exit(0);
    } else if (action === 'release') {
      emit({ action, released: lib.releaseLoopLock(lockPath, owner) });
      process.exit(0);
    } else {
      process.stderr.write(`Unknown action: ${String(action)} (expected acquire|refresh|release)\n`);
      process.exit(3);
    }
  } catch (error) {
    process.stderr.write(`[deep-context] loop-lock ${String(action)} failed: ${error instanceof Error ? error.message : String(error)}\n`);
    process.exit(1);
  }
}

if (require.main === module) {
  main();
}

module.exports = { parseArgs, loadLoopLock, main };

// ╔══════════════════════════════════════════════════════════════════════════╗
// ║ lib/rollback                                                             ║
// ╠══════════════════════════════════════════════════════════════════════════╣
// ║ Round rollback: move failed round artifacts and append supersede events  ║
// ╚══════════════════════════════════════════════════════════════════════════╝

'use strict';

// ─────────────────────────────────────────────────────────────────────────────
// 1. IMPORTS
// ─────────────────────────────────────────────────────────────────────────────

const fs = require('node:fs');
const path = require('node:path');
const { appendJsonlEvent, normalizeRoundId } = require('./audit-trail.cjs');

// ─────────────────────────────────────────────────────────────────────────────
// 2. CONSTANTS
// ─────────────────────────────────────────────────────────────────────────────

// ─────────────────────────────────────────────────────────────────────────────
// 3. HELPERS
// ─────────────────────────────────────────────────────────────────────────────

function safeTimestamp(timestamp) {
  return String(timestamp || new Date().toISOString()).replace(/[:.]/g, '-');
}

function moveIfExists(source, target) {
  if (!fs.existsSync(source)) return null;
  fs.mkdirSync(path.dirname(target), { recursive: true });
  fs.rmSync(target, { recursive: true, force: true });
  fs.renameSync(source, target);
  return target;
}

// ─────────────────────────────────────────────────────────────────────────────
// 4. CORE LOGIC
// ─────────────────────────────────────────────────────────────────────────────

/**
 * Move the selected round artifacts into a failed-round archive folder.
 *
 * @param {string} packetSpecFolder - Packet spec folder containing ai-council
 * @param {string|number} roundId - Round id or integer round number
 * @param {Object} [options={}] - Rollback options
 * @param {string} [options.timestamp] - Timestamp used in the failed folder
 * @returns {Object} Failed archive root and moved artifact paths
 */
function moveRoundToFailed(packetSpecFolder, roundId, options = {}) {
  const round = normalizeRoundId(roundId);
  const councilRoot = path.resolve(packetSpecFolder, 'ai-council');
  const failedRoot = path.join(councilRoot, 'failed', `${round}-${safeTimestamp(options.timestamp)}`);
  const moved = [];

  const candidates = [
    [path.join(councilRoot, round), path.join(failedRoot, round)],
    [path.join(councilRoot, 'seats', round), path.join(failedRoot, 'seats', round)],
    [path.join(councilRoot, 'deliberations', `${round}.md`), path.join(failedRoot, 'deliberations', `${round}.md`)],
    [path.join(councilRoot, 'critiques', `${round}-critique.md`), path.join(failedRoot, 'critiques', `${round}-critique.md`)],
  ];

  for (const [source, target] of candidates) {
    const movedPath = moveIfExists(source, target);
    if (movedPath) moved.push(movedPath);
  }

  return { round_id: round, failedRoot, moved };
}

function readEvents(stateJsonlPath) {
  if (!fs.existsSync(stateJsonlPath)) return [];
  return fs.readFileSync(stateJsonlPath, 'utf8')
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line) => JSON.parse(line));
}

/**
 * Append rollback and artifact_superseded markers for a round.
 *
 * @param {string} stateJsonlPath - Path to the state JSONL file
 * @param {Object} [options={}] - Supersede options
 * @param {string|number} [options.round_id] - Round id to mark superseded
 * @param {string|number} [options.roundId] - Camel-case round id alias
 * @param {string} [options.timestamp] - Event timestamp
 * @param {string} [options.rollback_event_id] - Rollback event id
 * @param {string} [options.rollbackEventId] - Camel-case rollback id alias
 * @param {string} [options.reason] - Rollback reason
 * @returns {Object} Superseded artifact summary
 */
function markSuperseded(stateJsonlPath, options = {}) {
  const round = normalizeRoundId(options.round_id || options.roundId || 1);
  const timestamp = options.timestamp || new Date().toISOString();
  const rollbackEventId = options.rollback_event_id || options.rollbackEventId || `rollback-${round}-${Date.now()}`;
  const reason = options.reason || 'round rollback';
  const events = readEvents(stateJsonlPath);
  const priorMarkers = new Set(
    events
      .filter((event) => event.event === 'artifact_superseded' && event.round_id === round)
      .map((event) => event.original_path),
  );
  const artifactEvents = events.filter(
    (event) => event.event === 'artifact_written' && event.round_id === round && !priorMarkers.has(event.path),
  );

  appendJsonlEvent(stateJsonlPath, {
    event: 'rollback',
    round_id: round,
    reason,
    timestamp,
    rollback_event_id: rollbackEventId,
    supersedes: artifactEvents.map((event) => event.event_id || event.path),
  });

  const appended = [];
  for (const artifact of artifactEvents) {
    appendJsonlEvent(stateJsonlPath, {
      event: 'artifact_superseded',
      original_path: artifact.path,
      round_id: round,
      rollback_event_id: rollbackEventId,
      superseded_by: 'rollback',
      timestamp,
    });
    appended.push(artifact.path);
  }

  return { round_id: round, rollback_event_id: rollbackEventId, superseded: appended };
}

// ─────────────────────────────────────────────────────────────────────────────
// 5. EXPORTS
// ─────────────────────────────────────────────────────────────────────────────

module.exports = {
  moveRoundToFailed,
  markSuperseded,
};

